import os
import base64
import re
import ipaddress
import zmq
import logging

logger = logging.getLogger(__name__)

class SecureClient:
    def __init__(self, guide_addr, ctx=None):
        self.guide_addr = guide_addr
        self.ctx = ctx or zmq.Context.instance()
        self._setup_socket()

    def _validate_host(self, host):
        host = host.strip()
        if not host:
            raise ValueError("Host part of GUIDE_ADDR cannot be empty")
        try:
            ipaddress.ip_address(host)
            return host
        except ValueError:
            pass
        if host.startswith('[') and host.endswith(']'):
            inner = host[1:-1]
            try:
                ipaddress.ip_address(inner)
                return inner
            except ValueError:
                pass
        if re.fullmatch(r"[A-Za-z0-9.-]+", host):
            return host
        raise ValueError(f"Invalid host component in GUIDE_ADDR: {host}")

    def _validate_port(self, port_str):
        try:
            port = int(port_str)
            if not (0 < port < 65536):
                raise ValueError
            return port
        except Exception:
            raise ValueError("GUIDE_ADDR contains an invalid port number")

    def _validate_curve_key(self, key, name):
        if not isinstance(key, str):
            raise ValueError(f"{name} must be a base64-encoded string")
        if len(key) != 40:
            raise ValueError(f"{name} must be exactly 40 characters long")
        try:
            decoded = base64.b64decode(key.encode(), validate=True)
            if len(decoded) != 32:
                raise ValueError
        except Exception:
            raise ValueError(f"{name} is not a valid CURVE key")
        return key.encode()

    def _setup_socket(self):
        if not isinstance(self.guide_addr, str) or ':' not in self.guide_addr:
            raise ValueError("GUIDE_ADDR must be a string in 'host:port' format")
        host_part, port_part = self.guide_addr.rsplit(':', 1)
        host = self._validate_host(host_part)
        port = self._validate_port(port_part)

        try:
            self.socket = self.ctx.socket(zmq.DEALER)
            self.socket.linger = 0

            client_pub = os.getenv('ZMQ_CLIENT_PUBLIC')
            client_sec = os.getenv('ZMQ_CLIENT_SECRET')
            server_pub = os.getenv('ZMQ_SERVER_PUBLIC')

            if not all([client_pub, client_sec, server_pub]):
                raise RuntimeError("CURVE encryption keys are missing; secure connection required")

            self.socket.curve_publickey = self._validate_curve_key(client_pub, "ZMQ_CLIENT_PUBLIC")
            self.socket.curve_secretkey = self._validate_curve_key(client_sec, "ZMQ_CLIENT_SECRET")
            self.socket.curve_serverkey = self._validate_curve_key(server_pub, "ZMQ_SERVER_PUBLIC")

            for var in ('ZMQ_CLIENT_PUBLIC', 'ZMQ_CLIENT_SECRET', 'ZMQ_SERVER_PUBLIC'):
                if var in os.environ:
                    del os.environ[var]

            self.socket.connect(f"tcp://{host}:{port}")
        except zmq.ZMQError as exc:
            logger.error("Failed to set up communication socket")
            raise RuntimeError("Communication setup failed") from exc

