#include <iostream>
#include <string>
#include <vector>
#include <regex>
#include <unistd.h>
#include <sys/wait.h>
#include <limits.h>
#include <cstring>
#include <cerrno>
#include <sys/types.h>
#include <sys/stat.h>
#include <fcntl.h>
#include <filesystem>
#include <unordered_set>

namespace fs = std::filesystem;

// ---------- Utilities ----------
static const std::unordered_set<std::string> allowed_build_cmds{
    "make",
    "ninja",
    "bazel"
};

// Minimal safe environment for execve
static const char *safe_envp[] = {
    "PATH=/usr/bin:/bin",
    nullptr
};

// Drop root privileges if running as root
void drop_privileges() {
    if (geteuid() == 0) {
        // Try to drop to nobody:nogroup (UID/GID 65534) – adjust as needed
        setgid(65534);
        setuid(65534);
    }
}

// Validate paths: no leading '/', no "..", allowed characters only
bool is_valid_path(const std::string &path) {
    static const std::regex pattern(R"(^(?!.*\.\.)(?!/)[\w.\-\/]+$)");
    return std::regex_match(path, pattern);
}

// Validate command names against whitelist
bool is_allowed_command(const std::string &cmd) {
    // Allow absolute path only if the basename is allowed
    std::string basename = cmd;
    auto pos = cmd.find_last_of('/');
    if (pos != std::string::npos) {
        basename = cmd.substr(pos + 1);
    }
    return allowed_build_cmds.find(basename) != allowed_build_cmds.end();
}

// Validate git revision: hex hash or simple ref name without ".."
bool is_valid_git_rev(const std::string &rev) {
    static const std::regex hex_rev(R"(^[0-9a-fA-F]{40,64}$)");
    static const std::regex name_rev(R"(^(?!.*\.\.)[A-Za-z0-9._\/-]+$)");
    return std::regex_match(rev, hex_rev) || std::regex_match(rev, name_rev);
}

// Execute a command with sanitized environment and minimal args
int exec_command(const std::string &executable,
                  const std::vector<std::string> &args) {
    pid_t pid = fork();
    if (pid < 0) {
        std::cerr << "fork failed: " << strerror(errno) << std::endl;
        return -1;
    }
    if (pid == 0) { // child
        // Build argv for execve
        std::vector<char *> argv;
        argv.reserve(args.size() + 2);
        argv.push_back(const_cast<char *>(executable.c_str()));
        for (const auto &a : args) {
            argv.push_back(const_cast<char *>(a.c_str()));
        }
        argv.push_back(nullptr);

        // Ensure the executable exists and is a regular file
        struct stat sb{};
        if (stat(executable.c_str(), &sb) != 0 || !S_ISREG(sb.st_mode)) {
            _exit(127);
        }

        // Drop privileges in child before exec
        drop_privileges();

        execve(executable.c_str(), argv.data(), const_cast<char **>(safe_envp));
        // If execve returns, it's an error
        _exit(127);
    }
    // parent
    int status = 0;
    if (waitpid(pid, &status, 0) == -1) {
        std::cerr << "waitpid failed: " << strerror(errno) << std::endl;
        return -1;
    }
    if (WIFEXITED(status)) {
        return WEXITSTATUS(status);
    }
    return -1;
}

// ---------- Secure Operations ----------
int safe_copy(const std::string &src, const std::string &dest) {
    if (!is_valid_path(src) || !is_valid_path(dest)) {
        std::cerr << "Unsafe path detected for copy operation." << std::endl;
        return -1;
    }

    // Resolve src to ensure it exists and is inside current working directory
    try {
        fs::path src_path = fs::canonical(src);
        fs::path cwd = fs::current_path();
        if (src_path.string().find(cwd.string()) != 0) {
            std::cerr << "Source path escapes working directory." << std::endl;
            return -1;
        }
    } catch (const fs::filesystem_error &) {
        std::cerr << "Source path does not exist or cannot be resolved." << std::endl;
        return -1;
    }

    // Destination may not exist yet; only check for unsafe components
    return exec_command("/usr/bin/rsync",
                        {"-a", src + "/", dest + "/"});
}

int git_checkout(const std::string &rev) {
    if (!is_valid_git_rev(rev)) {
        std::cerr << "Unsafe revision identifier." << std::endl;
        return -1;
    }
    // Verify that revision resolves to a commit
    int verify = exec_command("/usr/bin/git",
                              {"rev-parse", "--verify", rev + "^{commit}"});
    if (verify != 0) {
        std::cerr << "Git revision verification failed." << std::endl;
        return -1;
    }
    return exec_command("/usr/bin/git",
                         {"checkout", "-f", rev});
}

int git_clean() {
    return exec_command("/usr/bin/git",
                         {"clean", "-f", "-d"});
}

int run_build(const std::string &build_cmd,
              const std::string &dep_dir,
              const std::string &work_dir) {
    if (!is_allowed_command(build_cmd) ||
        !is_valid_path(dep_dir) ||
        !is_valid_path(work_dir)) {
        std::cerr << "Unsafe input for build command." << std::endl;
        return -1;
    }

    // Resolve dep_dir and work_dir to ensure they stay within cwd
    try {
        fs::path dep_path = fs::canonical(dep_dir);
        fs::path work_path = fs::canonical(work_dir);
        fs::path cwd = fs::current_path();
        if (dep_path.string().find(cwd.string()) != 0 ||
            work_path.string().find(cwd.string()) != 0) {
            std::cerr << "Dependency or work directory escapes working directory." << std::endl;
            return -1;
        }
    } catch (const fs::filesystem_error &) {
        std::cerr << "Dependency or work directory does not exist." << std::endl;
        return -1;
    }

    std::string exec_path = build_cmd; // could be absolute or in PATH
    return exec_command(exec_path, {"-p", dep_dir, work_dir});
}

// ---------- Main Workflow ----------
void perform_build(const std::string &rev,
                   const std::string &src_dir,
                   const std::string &dep_dir,
                   const std::string &build_cmd) {
    // Drop privileges early if running as root
    drop_privileges();

    const std::string work_dir = "__tmp" + rev;

    if (safe_copy(src_dir, work_dir) != 0) {
        std::cerr << "Failed to copy source directory." << std::endl;
        return;
    }

    char ori_dir_buf[PATH_MAX] = {0};
    if (!getcwd(ori_dir_buf, sizeof(ori_dir_buf))) {
        std::cerr << "Failed to get current working directory." << std::endl;
        return;
    }
    const std::string ori_dir = ori_dir_buf;

    if (chdir(work_dir.c_str()) != 0) {
        std::cerr << "Failed to change to work directory: " << strerror(errno) << std::endl;
        return;
    }

    if (git_checkout(rev) != 0) {
        std::cerr << "Git checkout failed." << std::endl;
        chdir(ori_dir.c_str());
        return;
    }

    if (git_clean() != 0) {
        std::cerr << "Git clean failed." << std::endl;
        chdir(ori_dir.c_str());
        return;
    }

    if (chdir(ori_dir.c_str()) != 0) {
        std::cerr << "Failed to return to original directory: " << strerror(errno) << std::endl;
        return;
    }

    if (run_build(build_cmd, dep_dir, work_dir) != 0) {
        std::cerr << "Build command failed." << std::endl;
    }

    // Optional cleanup (run as low‑privilege user)
    exec_command("/usr/bin/rm", {"-rf", work_dir});
}

