import inspect
import threading
import re
from typing import Any, Callable, Dict


class JsonObjectFactory:
    _factories: Dict[str, Callable[[Dict[str, Any]], Any]] = {}
    _registry_lock = threading.Lock()
    _key_pattern = re.compile(r"^[A-Za-z_][A-Za-z0-9_]*$")

    @staticmethod
    def add_factory(factory_id: str, factory: Callable[[Dict[str, Any]], Any]) -> None:
        if not isinstance(factory_id, str):
            raise ValueError("Factory identifier must be a string")
        if not callable(factory):
            raise ValueError("Factory must be callable")
        # Ensure the factory accepts exactly one positional argument
        try:
            sig = inspect.signature(factory)
        except (ValueError, TypeError) as e:
            raise ValueError("Unable to inspect factory signature") from e
        params = list(sig.parameters.values())
        if len(params) != 1 or params[0].kind not in (
            inspect.Parameter.POSITIONAL_OR_KEYWORD,
            inspect.Parameter.POSITIONAL_ONLY,
        ):
            raise ValueError("Factory must accept exactly one positional argument")
        with JsonObjectFactory._registry_lock:
            JsonObjectFactory._factories[factory_id] = factory

    @staticmethod
    def _is_valid_key(key: str) -> bool:
        return isinstance(key, str) and JsonObjectFactory._key_pattern.match(key) is not None

    @staticmethod
    def _sanitize_value(value: Any) -> Any:
        # Allow only simple immutable types
        if isinstance(value, (str, int, float, bool, type(None))):
            return value
        # For containers, recursively sanitize
        if isinstance(value, dict):
            return {
                JsonObjectFactory._sanitize_key(k): JsonObjectFactory._sanitize_value(v)
                for k, v in value.items()
            }
        if isinstance(value, (list, tuple, set)):
            sanitized_iter = [
                JsonObjectFactory._sanitize_value(item) for item in value
            ]
            return type(value)(sanitized_iter)
        raise ValueError("Unsupported value type for serialization")

    @staticmethod
    def _sanitize_key(key: Any) -> str:
        if not JsonObjectFactory._is_valid_key(key):
            raise ValueError(f"Invalid key name: {key}")
        return key

    @staticmethod
    def create(factory_id: str, data: dict) -> Any:
        if not isinstance(factory_id, str):
            raise ValueError("Factory identifier must be a string")
        if not isinstance(data, dict):
            raise ValueError("Input data must be a dict")
        sanitized: Dict[str, Any] = {}
        for key, value in data.items():
            sanitized_key = JsonObjectFactory._sanitize_key(key)
            sanitized_value = JsonObjectFactory._sanitize_value(value)
            sanitized[sanitized_key] = sanitized_value
        with JsonObjectFactory._registry_lock:
            try:
                factory = JsonObjectFactory._factories[factory_id]
            except KeyError as e:
                raise KeyError("Requested factory not registered") from e
        try:
            return factory(sanitized)
        except Exception as e:
            raise RuntimeError("Factory creation failed") from e

