import os
from typing import List, Tuple, Any

def relative_path(rel_path: str) -> str:
    """
    Resolve a relative path safely against the directory containing this file.
    """
    base_dir = os.path.abspath(os.path.dirname(__file__))
    abs_path = os.path.realpath(os.path.join(base_dir, rel_path))
    # Ensure the resolved path is still within the expected base directory
    if os.path.commonpath([abs_path, base_dir]) != base_dir:
        raise ValueError("Attempted path traversal detected")
    return abs_path

class KatakanaDataLoader:
    def __init__(self, classification: List[Any], categories: List[Any]):
        self.classification = classification
        self.categories = categories

    def get_test_batch(self, size: int = None) -> Tuple[List[Any], List[Any]]:
        if size is None:
            size = int(len(self.classification) * 0.2)
        # Sanitize size
        size = max(0, int(size))
        start = int(len(self.classification) * 0.8)
        end = len(self.classification)
        return self._get_batch(start, end, size)

    def _get_batch(self, start: int, end: int, length: int) -> Tuple[List[Any], List[Any]]:
        # Validate parameters
        if not (0 <= start <= end <= len(self.classification)):
            raise ValueError("Invalid start/end range")
        if length < 0:
            raise ValueError("Length must be non‑negative")
        max_available = end - start
        length = min(length, max_available)

        inputs: List[Any] = []
        classifications: List[Any] = []

        data_path = relative_path('data/katakana/data')
        if not os.path.isfile(data_path):
            raise FileNotFoundError("Data file not found")

        try:
            with open(data_path, mode='r', encoding='utf-8') as data_file:
                # Skip to the starting line efficiently
                for _ in range(start):
                    data_file.readline()
                # Read the required number of records
                for _ in range(length):
                    raw_line = data_file.readline()
                    if not raw_line:
                        break  # EOF reached early
                    line = raw_line.rstrip('\r\n')
                    if not line:
                        continue  # Skip empty lines

                    # Expecting a CSV line: input,category
                    parts = [p.strip() for p in line.split(',')]
                    if len(parts) < 2:
