                        continue
                    if any(ord(ch) < 32 for ch in cat):
                        continue

                    inputs.append(inp)
                    classifications.append(cat)
        except OSError:
            # Generic error without leaking filesystem details
            raise RuntimeError("Failed to read data batch") from None

        return inputs, classifications

