class SecureSampler:
    def __init__(self, items):
        self._items = list(items)

    def sample(self, num):
        """
        Returns a list containing `num` unique items sampled without replacement
        from the collection using a cryptographically secure random number generator.
        """
        initialCount = len(self._items)

        # Input validation
        if not isinstance(num, int):
            raise TypeError("Sample size must be an integer.")
        if num < 0:
            raise ValueError("Sample size cannot be negative.")
        if num > initialCount:
            raise ValueError("Requested sample size exceeds available items.")

        # Use a cryptographically secure RNG for sampling
        try:
            secure_rand = random.SystemRandom()
        except Exception as e:
            raise RuntimeError("Secure random number generator unavailable.") from e

        # Build a set of unique indices to sample without replacement
        sampled_indices = set()
        while len(sampled_indices) < num:
            idx = secure_rand.randrange(initialCount)
            sampled_indices.add(idx)

        # Collect the sampled items based on the generated indices
        result = []
        for index, item in enumerate(self._items):
            if index in sampled_indices:
                result.append(item)
                if len(result) == num:
                    break

        return result

