class RestrictedUnpickler(pickle.Unpickler):
    _SAFE_BUILTINS = {
        "dict",
        "list",
        "tuple",
        "set",
        "frozenset",
        "str",
        "bytes",
        "int",
        "float",
        "bool",
    }

    def find_class(self, module, name):
        if module == "builtins" and name in self._SAFE_BUILTINS:
            return getattr(__builtins__, name)
        raise pickle.UnpicklingError(f"Disallowed class {module}.{name}")


def _check_structure(obj, depth=0, visited=None):
    if visited is None:
        visited = set()
    if depth > MAX_PICKLE_DEPTH:
        raise ValueError("Pickle structure exceeds maximum depth")
    if isinstance(obj, (list, tuple, set, frozenset)):
        if len(obj) > MAX_PICKLE_ITEMS:
            raise ValueError("Pickle collection exceeds maximum size")
