class TurqTestController:
    """Spins up and controls a live instance of Turq for testing."""

    def __init__(self, turq_path: str = "turq"):
        self.host = "localhost"
        self.mock_port = 13095
        self.editor_port = 13096
        self._process = None
        self._turq_path = Path(turq_path).resolve()
        self._validate_executable()

    def _validate_executable(self):
        if not self._turq_path.is_file():
            raise FileNotFoundError("Turq executable not found")
        if not os.access(self._turq_path, os.X_OK):
            raise PermissionError("Turq executable is not executable")
        if not any(self._turq_path.is_relative_to(d) for d in TRUSTED_DIRS):
            raise PermissionError(
                f"Turq executable must reside in a trusted directory: {', '.join(map(str, TRUSTED_DIRS))}"
            )

    @staticmethod
    def _validate_port(port: int):
        if not isinstance(port, int):
            raise TypeError("Port must be an integer")
        if not (1 <= port <= 65535):
            raise ValueError("Port out of valid range (1-65535)")

    def _preexec(self):
        # Re‑validate the executable right before exec to mitigate TOCTOU
        try:
            self._validate_executable()
        except Exception:
            logger.error("Executable validation failed in child process")
            os._exit(1)
        self._drop_privileges()

    def start(self):
        try:
            self._validate_port(self.mock_port)
            self._validate_port(self.editor_port)
        except Exception:
            logger.error("Invalid port configuration")
            raise

        cmd = [
            str(self._turq_path),
            "--host",
            self.host,
            "--port",
            str(self.mock_port),
            "--editor-port",
            str(self.editor_port),
        ]

        env = {"PATH": SAFE_PATH, "LANG": "C.UTF-8"}
        try:
            self._process = subprocess.Popen(
                cmd,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                env=env,
                close_fds=True,
                preexec_fn=self._preexec if hasattr(os, "setuid") else None,
                shell=False,
            )
        except Exception as exc:
            logger.exception("Failed to start Turq process")
            raise RuntimeError("Unable to start Turq") from exc

        for _ in range(30):
            if self._process.poll() is not None:
                out, err = self._process.communicate()
                logger.error("Turq terminated early: %s", err.decode(errors="ignore"))
                raise RuntimeError("Turq failed to start")
            if self._is_port_open(self.mock_port):
                logger.info("Turq started on port %s", self.mock_port)
                return
            time.sleep(0.5)

        self.stop()
        raise TimeoutError("Turq did not become reachable in time")

    def _drop_privileges(self):
        try:
            import pwd

            nobody = pwd.getpwnam("nobody")
            os.setgid(nobody.pw_gid)
            os.setuid(nobody.pw_uid)
        except Exception as e:
            logger.error("Failed to drop privileges: %s", e)
            os._exit(1)

    @staticmethod
    def _is_port_open(port: int) -> bool:
        with closing(socket.socket(socket.AF_INET, socket.SOCK_STREAM)) as sock:
            sock.settimeout(0.2)
            return sock.connect_ex(("localhost", port)) == 0

    def stop(self):
        if self._process and self._process.poll() is None:
            try:
                self._process.terminate()
                try:
                    self._process.wait(timeout=5)
                except subprocess.TimeoutExpired:
                    self._process.kill()
                    self._process.wait()
                logger.info("Turq process stopped")
            except Exception:
                logger.exception("Error stopping Turq")
        self._process = None

    def send_command(self, command: str, timeout: float = 2.0) -> str:
        if not isinstance(command, str):
            raise TypeError("Command must be a string")
        sanitized = command.strip()
        if not sanitized:
            raise ValueError("Command cannot be empty")
        if not _COMMAND_REGEX.fullmatch(sanitized):
            raise ValueError("Command contains prohibited characters")

        with closing(
            socket.create_connection((self.host, self.mock_port), timeout=timeout)
        ) as sock:
            sock.settimeout(timeout)
            sock.sendall(sanitized.encode("utf-8") + b"\n")
            sock.shutdown(socket.SHUT_WR)

            response = b""
            try:
