# Configure a module‑level logger (no handlers added here to avoid side‑effects)
logger = logging.getLogger(__name__)

def _validate_numeric_array(x):
    """Validate that *x* is a 1‑D numeric sequence without NaNs or infinities."""
    if isinstance(x, (list, tuple, np.ndarray)):
        arr = np.asarray(x, dtype=np.float64)
    else:
        raise TypeError("Input data must be a list, tuple, or numpy array.")
    if arr.ndim != 1:
        raise ValueError("Input data must be one‑dimensional.")
    if arr.size == 0:
        raise ValueError("Input data must contain at least one element.")
    if np.isnan(arr).any() or ~np.isfinite(arr).all():
        raise ValueError("Input data must not contain NaN or infinite values.")
    return arr

def _validate_bracket(brack):
    """Validate that *brack* is a two‑element sequence of finite numbers with low < high."""
    if not isinstance(brack, (list, tuple)):
        raise TypeError("brack must be a tuple/list of two numbers.")
    if len(brack) != 2:
        raise ValueError("brack must contain exactly two elements.")
    low, high = brack
    if not isinstance(low, (int, float, np.integer, np.floating)):
        raise TypeError("Bracket bounds must be numeric.")
    if not isinstance(high, (int, float, np.integer, np.floating)):
        raise TypeError("Bracket bounds must be numeric.")
    low = float(low)
    high = float(high)
    if not np.isfinite(low) or not np.isfinite(high):
        raise ValueError("Bracket bounds must be finite numbers.")
    if low >= high:
        raise ValueError("Bracket lower bound must be less than upper bound.")
    return low, high

def _validate_distribution(dist):
    """Validate that *dist* is one of the supported distribution names."""
    allowed = {"tukeylambda", "beta", "gamma", "chi2", "norm"}
    if not isinstance(dist, str):
        raise TypeError("dist must be a string.")
    normalized = dist.lower()
    if normalized not in allowed:
        raise ValueError(f"Unsupported distribution '{dist}'. Allowed: {sorted(allowed)}.")
    return normalized

def _ppcc_correlation(shape, data, dist_name):
    """Return the absolute Pearson correlation for a given shape parameter."""
    dist_map = {
        "tukeylambda": stats.tukeylambda,
        "beta": stats.beta,
        "gamma": stats.gamma,
        "chi2": stats.chi2,
        "norm": stats.norm,
    }
    dist_obj = dist_map[dist_name]
    # Ensure shape is a finite scalar
    if not isinstance(shape, (int, float, np.integer, np.floating)):
        raise TypeError("Shape parameter must be numeric.")
    shape = float(shape)
    if not np.isfinite(shape):
        raise ValueError("Shape parameter must be a finite number.")
    # Generate quantile–quantile data
    osm, osr = stats.probplot(data, dist=dist_obj, sparams=(shape,))
    # Compute Pearson correlation; safeguard against NaN
    r = np.corrcoef(osm, osr)[0, 1]
    if np.isnan(r):
        return 0.0
    return abs(r)

def ppcc_max(x, brack=(0.0, 1.0), dist="tukeylambda"):
    """Find the shape parameter that maximizes the PPCC for *x*."""
    try:
        data = _validate_numeric_array(x)
        low, high = _validate_bracket(brack)
        dist_name = _validate_distribution(dist)

        def objective(shape):
            try:
                return -_ppcc_correlation(shape, data, dist_name)
            except Exception as exc:
                logger.debug("Correlation computation failed for shape %s: %s", shape, exc)
                # Return a large penalty so the optimizer discards this region
                return 1e6

        result = optimize.minimize_scalar(
            objective,
            bounds=(low, high),
            method="bounded",
            options={"xatol": 1e-6},
        )

        if not result.success:
            raise RuntimeError("Optimization did not converge.")

