def hash_file(file_like_object, algorithm='sha256', chunk_size=8192):
    """
    Generate a cryptographic hash for the contents of a file-like object.

    Args:
        file_like_object: An object exposing a binary ``read()`` method.
        algorithm (str): Hash algorithm to use; defaults to ``sha256``.
        chunk_size (int): Number of bytes to read per iteration; defaults to 8 KB.

    Returns:
        str: Hexadecimal digest of the file contents.

    Raises:
        ValueError: If inputs are invalid.
        RuntimeError: If an I/O error occurs while reading.
    """
    import hashlib

    # Validate the file_like_object
    if not hasattr(file_like_object, 'read') or not callable(file_like_object.read):
        raise ValueError("Provided object does not have a callable 'read' method.")

    # Validate algorithm against a whitelist of secure hashes
    allowed_algos = {'sha256', 'sha384', 'sha512'}
    if not isinstance(algorithm, str) or algorithm.lower() not in allowed_algos:
        raise ValueError(f"Unsupported hash algorithm: {algorithm}")

    # Validate chunk size
    if not isinstance(chunk_size, int) or chunk_size <= 0:
        raise ValueError("Chunk size must be a positive integer.")

    hasher = hashlib.new(algorithm.lower())

    try:
        while True:
            data = file_like_object.read(chunk_size)
            if not data:
                break
            if not isinstance(data, (bytes, bytearray)):
                raise ValueError("File-like object must return bytes.")
            hasher.update(data)
    except (OSError, IOError, ValueError, TypeError):
        raise RuntimeError("Failed to compute file hash.")
    except Exception:
        raise RuntimeError("Failed to compute file hash.")

    return hasher.hexdigest()

