def read_message_file(msg_path: str, safe_name: str, max_file_size: int = 1024 * 1024):
    """
    Reads a message file and returns either a parsed JSON object (if the first
    non‑empty line starts with '[') or the raw text line. Returns None on error
    or when the file is empty.
    """
    # Validate input types
    if not isinstance(msg_path, str) or not isinstance(safe_name, str):
        logger.error("Invalid arguments: msg_path and safe_name must be strings")
        return None

    # Prevent directory traversal attacks
    if os.path.sep in safe_name or (os.path.altsep and os.path.altsep in safe_name):
        logger.error("Unsafe filename detected: %s", safe_name)
        return None

    full_path = os.path.abspath(os.path.join(msg_path, safe_name))
    base_dir = os.path.abspath(msg_path)

    if not full_path.startswith(base_dir + os.path.sep):
        logger.error("Resolved path escapes base directory: %s", full_path)
        return None

    # Size check before reading
    try:
        if os.path.getsize(full_path) > max_file_size:
            logger.error("File too large: %s", full_path)
            return None
    except OSError as e:
        logger.error("Unable to stat file %s: %s", full_path, e)
        return None

    result = None
