def _safe_int(value: str, name: str) -> int:
    try:
        iv = int(value)
        if iv < 0:
            raise ValueError
        return iv
    except Exception:
        logging.error("Invalid %s value: %s", name, value)
        sys.exit(1)


def _is_regular_file(path: Path) -> bool:
    """Return True only if path exists, is a regular file and is not a symlink."""
    try:
        st = path.lstat()
        return stat.S_ISREG(st.st_mode) and not stat.S_ISLNK(st.st_mode)
    except FileNotFoundError:
        return False


def _ensure_within_base(path: Path) -> Path:
    """Resolve path and ensure it stays within BASE_DIR."""
    resolved = path.resolve()
    try:
        resolved.relative_to(BASE_DIR)
    except ValueError:
        logging.error("Path %s is outside the allowed base directory %s", resolved, BASE_DIR)
        sys.exit(1)
    return resolved


