        # Decode bytes to str using the file system encoding
        if isinstance(fn, bytes):
            fn_path = fn.decode(sys.getfilesystemencoding(), errors="strict")
        else:
            fn_path = fn

        # Resolve the requested path to its canonical location
        abs_path = Path(fn_path).resolve()
    except (OSError, ValueError, UnicodeDecodeError):
        return KNH_DATA

    # Ensure the resolved path is a regular file within the base directory
    if not abs_path.is_file() or base_dir not in abs_path.parents:
        return KNH_DATA

    # Read and parse the JSON file
