MAX_PAYLOAD_SIZE = 10 * 1024  # 10 KB
MIN_CRED_LENGTH = 8

# Retrieve credentials from environment (or other secure store)
username = os.getenv("SINA_API_USERNAME")
password = os.getenv("SINA_API_PASSWORD")

def _is_valid_credential(value: str) -> bool:
    """Validate credential characters and enforce minimum length."""
    if not isinstance(value, str):
        return False
    if len(value) < MIN_CRED_LENGTH:
        return False
    return bool(re.fullmatch(r"[A-Za-z0-9_\-\.]+", value))

if not (username and password):
    logger.error("Missing API credentials.")
    raise ValueError("API credentials must be set in environment variables.")

if not (_is_valid_credential(username) and _is_valid_credential(password)):
    logger.error("Invalid login credential format.")
    raise ValueError("Invalid credentials")

def _is_allowed_endpoint(endpoint: str) -> bool:
    """Ensure endpoint does not contain traversal, schema, or leading slash."""
    if not isinstance(endpoint, str):
        return False
    # Disallow absolute URLs or scheme-relative URLs
    if urlparse(endpoint).scheme or endpoint.startswith("//"):
        return False
    # Disallow path traversal
    if ".." in endpoint:
        return False
    # Disallow leading slash to avoid double-slash after join
    if endpoint.startswith("/"):
        return False
    return True

def _validate_payload(payload: dict) -> None:
    """Validate payload type and size."""
    if not isinstance(payload, dict):
        raise ValueError("Payload must be a dictionary.")
    try:
        payload_bytes = json.dumps(payload).encode("utf-8")
    except (TypeError, ValueError) as exc:
        raise ValueError("Payload contains non‑JSON‑serializable data.") from exc
    if len(payload_bytes) > MAX_PAYLOAD_SIZE:
        raise ValueError(f"Payload exceeds maximum size of {MAX_PAYLOAD_SIZE} bytes.")

def _post(endpoint: str, payload: dict) -> dict:
    """Send a JSON POST request with basic auth, safe defaults."""
    if not _is_allowed_endpoint(endpoint):
        logger.error("Disallowed endpoint: %s", endpoint)
        raise ValueError("Invalid endpoint")
    url = urljoin(API_BASE + "/", endpoint)
    # Ensure the final URL is still within the intended host
    parsed_base = urlparse(API_BASE)
    parsed_url = urlparse(url)
    if parsed_url.netloc != parsed_base.netloc:
        logger.error("Endpoint resolved to a different host: %s", url)
        raise ValueError("Endpoint resolves outside allowed domain")
    _validate_payload(payload)
    try:
        response = requests.post(
            url,
            json=payload,
            auth=(username, password),
            timeout=REQUEST_TIMEOUT,
            verify=True,
        )
