import os
import json
import tempfile
import shutil
from pathlib import Path
from typing import Any, Dict, Iterable, Tuple, Optional


class SimpleShelf:
    """
    A minimal JSON‑backed key/value store.
    """

    def __init__(self, file_path: Path, mode: str):
        if not isinstance(file_path, Path):
            raise TypeError("file_path must be a pathlib.Path")
        if mode not in {"n", "r"}:
            raise ValueError(f"Unsupported mode: {mode!r}")

        self.file_path = file_path
        self.mode = mode
        self._data: Dict[str, Any] = {}

        if mode == "n":  # new file for recording
            self._data = {}
        else:  # read‑only for playback
            try:
                with self.file_path.open("r", encoding="utf-8") as f:
                    self._data = json.load(f)
            except FileNotFoundError as exc:
                raise RuntimeError(f"Playback file not found: {self.file_path}") from exc
            except json.JSONDecodeError as exc:
                raise RuntimeError(f"Corrupted playback file: {self.file_path}") from exc

    def __getitem__(self, key: str) -> Any:
        return self._data[key]

    def __setitem__(self, key: str, value: Any) -> None:
        if self.mode != "n":
            raise RuntimeError("Shelf is read‑only")
        self._data[key] = value

    def __contains__(self, key: str) -> bool:
        return key in self._data

    def get(self, key: str, default: Any = None) -> Any:
        return self._data.get(key, default)

    def items(self) -> Iterable[Tuple[str, Any]]:
        return self._data.items()

    def close(self) -> None:
        """
        Persist data to disk only for recording shelves.
        Uses an atomic write to avoid race‑condition or partial‑write attacks.
        """
        if self.mode != "n":
            return

        # Ensure the parent directory exists
        self.file_path.parent.mkdir(parents=True, exist_ok=True)

        # Write to a temporary file in the same directory, then rename
        try:
            with tempfile.NamedTemporaryFile(
                mode="w",
                encoding="utf-8",
                dir=str(self.file_path.parent),
                delete=False,
                prefix=".tmp_",
                suffix=".json",
            ) as tmp:
                json.dump(self._data, tmp, ensure_ascii=False, indent=2)
                tmp.flush()
                os.fsync(tmp.fileno())
                temp_path = Path(tmp.name)

            # Set restrictive permissions (read/write for owner only)
            temp_path.chmod(0o600)

            # Atomic replacement
            temp_path.replace(self.file_path)
        except Exception as exc:
            raise RuntimeError(f"Failed to write recording file: {self.file_path}") from exc


class SecureRecorder:
    """
    Manages recording and playback of JSON‑based shelves within a confined base directory.
    """

    def __init__(self, base_dir: Optional[str] = None):
        self.recording_shelf: Optional[SimpleShelf] = None
        self.playback_shelf: Optional[SimpleShelf] = None
