import os
import pathlib
import subprocess
from typing import Union

class OfeliaDebianVMConfigurator:
    logger = logging.getLogger(__name__)

    @staticmethod
    def regenerate_ssh_keys(path: Union[str, pathlib.Path]) -> None:
        try:
            # ---------- Input validation ----------
            if not isinstance(path, (str, pathlib.Path)):
                raise ValueError("Invalid path type")
            base_path = pathlib.Path(path).resolve()
            if not base_path.is_absolute():
                raise ValueError("Base path must be absolute")
            # Ensure the directory exists and is a directory right now
            if not (base_path.is_dir() and not base_path.is_symlink()):
                raise FileNotFoundError(f"Base path does not exist or is not a directory: {base_path}")

            # Verify that the chroot environment looks sane (required binaries/files exist)
            required_paths = [
                base_path / "bin" / "sh",
                base_path / "etc" / "passwd",
                base_path / "etc" / "ssh",
            ]
            for req in required_paths:
                if not req.exists():
                    raise FileNotFoundError(f"Required file missing in chroot environment: {req}")

            ssh_dir = base_path / "etc" / "ssh"
            # Re‑validate ssh_dir right before use
            if not (ssh_dir.is_dir() and not ssh_dir.is_symlink()):
                raise FileNotFoundError(f"SSH directory not found or is not a directory: {ssh_dir}")

            # ---------- Safe removal of existing host keys ----------
            for key_file in ssh_dir.glob("ssh_host_*"):
                try:
                    # Ensure we are deleting a regular file, not a symlink, and have write permission
                    if key_file.is_file() and not key_file.is_symlink():
                        if os.access(key_file, os.W_OK):
                            key_file.unlink(missing_ok=True, follow_symlinks=False)
                        else:
                            OfeliaDebianVMConfigurator.logger.warning(
                                f"Insufficient permissions to delete {key_file}"
                            )
                    else:
                        OfeliaDebianVMConfigurator.logger.debug(
                            f"Skipped non‑regular or symlink file: {key_file}"
                        )
                except Exception as exc:
                    OfeliaDebianVMConfigurator.logger.warning(
                        f"Unable to delete old SSH key {key_file}: {type(exc).__name__}"
                    )

            # ---------- Generate new SSH host keys ----------
            key_specs = [
                ("rsa", "4096"),
                ("ed25519", None),
            ]
            for key_type, key_size in key_specs:
                cmd = [
                    "chroot",
                    str(base_path),
                    "ssh-keygen",
                    "-t",
                    key_type,
                    "-f",
                    f"/etc/ssh/ssh_host_{key_type}_key",
                    "-N",
                    "",
                ]
                if key_size:
                    cmd.extend(["-b", key_size])

                try:
                    result = subprocess.run(
                        cmd,
                        check=True,
                        capture_output=True,
                        text=True,
                    )
                    # Log debug output only; do not expose sensitive data to normal logs
                    OfeliaDebianVMConfigurator.logger.debug(
                        f"ssh-keygen output ({key_type}): {result.stdout}"
                    )
                    if result.stderr:
                        OfeliaDebianVMConfigurator.logger.debug(
                            f"ssh-keygen stderr ({key_type}): {result.stderr}"
                        )
                except subprocess.CalledProcessError as cpe:
                    OfeliaDebianVMConfigurator.logger.error(
                        f"Failed to generate {key_type} host key: {cpe.stderr or cpe}"
                    )
                    raise

            OfeliaDebianVMConfigurator.logger.info("SSH host keys regenerated successfully.")
        except Exception as e:
            OfeliaDebianVMConfigurator.logger.error(
                f"Failed to configure SSH server: {type(e).__name__}: {e}"
            )
            raise

