import ast
import logging
from typing import Any, Dict

logger = logging.getLogger(__name__)

_allowed_literal_types = (int, float, str, bool, type(None), tuple, list, dict, set, frozenset)


def _validate_locals(locals_dict: Dict[str, Any]) -> Dict[str, Any]:
    """Return a sanitized copy of locals_dict containing only safe values."""
    safe_locals: Dict[str, Any] = {}
    for key, value in locals_dict.items():
        if not isinstance(key, str):
            raise TypeError("All keys in locals_dict must be strings")
        if isinstance(value, _allowed_literal_types):
            safe_locals[key] = value
        else:
            raise TypeError(f"Value for key '{key}' is of an unsupported type")
    return safe_locals


def _is_safe_expression(node: ast.AST) -> bool:
    """Recursively ensure the AST node contains only safe constructs."""
    # Disallow any statements, imports, function definitions, etc.
    allowed_nodes = (
        ast.Expression,
        ast.BoolOp,
        ast.BinOp,
        ast.UnaryOp,
        ast.Lambda,
        ast.IfExp,
        ast.Dict,
        ast.Set,
        ast.ListComp,
        ast.SetComp,
        ast.DictComp,
        ast.GeneratorExp,
        ast.Await,
        ast.Yield,
        ast.YieldFrom,
        ast.Compare,
        ast.Call,
        ast.Num,
        ast.Str,
        ast.Bytes,
        ast.NameConstant,
        ast.Ellipsis,
        ast.Constant,
        ast.Attribute,
        ast.Subscript,
        ast.Starred,
        ast.Name,
        ast.List,
        ast.Tuple,
        ast.Load,
        ast.Store,
        ast.Del,
        ast.Slice,
        ast.Index,
        ast.ExtSlice,
    )
    if not isinstance(node, allowed_nodes):
        return False
    # Disallow calls to exec, eval, __import__, open, or any attribute starting with "__"
    if isinstance(node, ast.Call):
        if isinstance(node.func, ast.Name):
            if node.func.id in {"exec", "eval", "open", "__import__"}:
                return False
        if isinstance(node.func, ast.Attribute):
            if node.func.attr.startswith("__"):
                return False
    if isinstance(node, ast.Attribute):
        if node.attr.startswith("__"):
            return False
    for child in ast.iter_child_nodes(node):
        if not _is_safe_expression(child):
            return False
    return True


def _safe_eval(expr: str, locals_dict: Dict[str, Any]) -> Any:
    """Safely evaluate a Python expression using a restricted environment."""
    try:
        parsed = ast.parse(expr, mode="eval")
    except SyntaxError as e:
        raise ValueError("Provided string is not a valid Python expression") from e

    if not _is_safe_expression(parsed):
        raise ValueError("Expression contains disallowed constructs")

    safe_globals = {"__builtins__": {}}
    return eval(compile(parsed, filename="<safe_eval>", mode="eval"), safe_globals, locals_dict)


def _safe_exec(exec_str: str, locals_dict: Dict[str, Any]) -> None:
    """
    Execute a Python expression in a restricted environment.
    Only the provided locals are available; built‑ins are disabled.
    """
    if not isinstance(exec_str, str):
        raise TypeError("exec_str must be a string")
    if not isinstance(locals_dict, dict):
        raise TypeError("locals_dict must be a dict")

    sanitized_locals = _validate_locals(locals_dict)
    # The original intent is to execute code; we limit this to safe expression evaluation.
    _safe_eval(exec_str, sanitized_locals)


if RUN_DEV:
