import logging
import os
import json
from pathlib import Path

import numpy as np

logger = logging.getLogger(__name__)
logger.setLevel(logging.INFO)
handler = logging.StreamHandler()
handler.setFormatter(logging.Formatter("%(asctime)s %(levelname)s %(message)s"))
logger.addHandler(handler)

MAX_FILE_SIZE = 10 * 1024 * 1024  # 10 MiB
MAX_JSON_ARRAY_LENGTH = 1_000_000
MAX_JSON_NESTING_DEPTH = 20
MAX_TOTAL_JSON_ELEMENTS = 5_000_000
ALLOWED_EXT = {".json"}

RESULTS_DIR = Path("./results").resolve()
CACHE_DIR = Path("./cache").resolve()


def _is_within_directory(base_dir: Path, target_path: Path) -> bool:
    try:
        base = base_dir.resolve()
        target = target_path.resolve()
        try:
            return target.is_relative_to(base)  # Python 3.9+
        except AttributeError:
            return os.path.commonpath([str(target), str(base)]) == str(base)
    except Exception:
        return False


def _check_json_limits(obj, depth=0, counters=None):
    if counters is None:
        counters = {"elements": 0}
    if depth > MAX_JSON_NESTING_DEPTH:
        raise ValueError("JSON nesting depth exceeds safe limit.")
    if isinstance(obj, dict):
        counters["elements"] += len(obj)
        for v in obj.values():
            _check_json_limits(v, depth + 1, counters)
    elif isinstance(obj, list):
        counters["elements"] += len(obj)
        for item in obj:
            _check_json_limits(item, depth + 1, counters)
    else:
        # Primitive types count as a single element
        counters["elements"] += 1
    if counters["elements"] > MAX_TOTAL_JSON_ELEMENTS:
        raise ValueError("JSON contains too many elements.")
    return obj


def _open_secure_file(file_path: Path, base_dir: Path) -> "io.TextIOWrapper":
    """
    Open a file safely:
    * O_NOFOLLOW prevents following symlinks.
    * After opening, re‑validate that the resolved real path is within base_dir.
    * Enforce size limit and basic JSON sniffing.
    Returns a text file object.
    """
    # Ensure file has correct extension before any OS operation
    if file_path.suffix.lower() not in ALLOWED_EXT:
        raise ValueError(f"Unsupported file extension: {file_path.suffix}")

    # Open without following symlinks
    fd = os.open(str(file_path), os.O_RDONLY | os.O_NOFOLLOW)
    try:
        # Verify the opened file is a regular file and size limit
        st = os.fstat(fd)
        if not os.path.S_ISREG(st.st_mode):
            raise ValueError("Target is not a regular file.")
        if st.st_size > MAX_FILE_SIZE:
            raise ValueError("File exceeds maximum allowed size.")

        # Resolve the actual filesystem path of the opened descriptor
        real_path = Path(os.readlink(f"/proc/self/fd/{fd}")).resolve()
        if not _is_within_directory(base_dir, real_path):
            raise ValueError("File path is outside the allowed directory.")

        # Create a text wrapper for JSON parsing
        file_obj = os.fdopen(fd, "r", encoding="utf-8")
        # Peek first non‑whitespace character to confirm JSON
        first_char = ""
        while True:
            ch = file_obj.read(1)
            if not ch:
                break
            if not ch.isspace():
                first_char = ch
                break
        if first_char not in ("{", "["):
            raise ValueError("File does not appear to contain JSON data.")
        # Reset to start for full parsing
        file_obj.seek(0)
        return file_obj
    except Exception:
        os.close(fd)
        raise


def _load_json_file(path: Path, base_dir: Path):
    try:
        with _open_secure_file(path, base_dir) as f:
            raw_data = json.load(f, object_hook=lambda o: _check_json_limits(o))
        # Additional top‑level array length check
        if isinstance(raw_data, (list, tuple)):
            if len(raw_data) > MAX_JSON_ARRAY_LENGTH:
                raise ValueError("JSON array exceeds maximum allowed length.")
        return raw_data
    except json.JSONDecodeError:
        logger.error("Failed to decode JSON from %s", path.name)
        raise RuntimeError("Unable to parse JSON data.")
    except ValueError as ve:
        logger.error("Validation error for %s: %s", path.name, ve)
        raise
    except Exception as exc:
        logger.error("Unexpected error loading %s: %s", path.name, exc)
        raise RuntimeError("Unable to read data.") from exc


def _load_result_file(result_path: Path):
    return _load_json_file(result_path, RESULTS_DIR)


def _read_json_cache(cache_path: Path):
    if not cache_path.is_file():
        logger.info("Cache file does not exist: %s", cache_path.name)
        return None
    try:
        data = _load_json_file(cache_path, CACHE_DIR)
        if isinstance(data, dict) and "latest" in data:
            return data["latest"]
        return None
    except Exception as exc:
        logger.error("Cache loading failed for %s: %s", cache_path.name, exc)
        raise RuntimeError("Cache operation failed.") from exc


def _convert_to_numpy(data):
    try:
        if isinstance(data, (list, tuple)):
            if len(data) > MAX_JSON_ARRAY_LENGTH:
                raise ValueError("Data array exceeds safe length.")
            return np.array(data)
        if hasattr(data, "__array__"):
            return np.array(data)
        logger.warning("Result data type not directly convertible to numpy array.")
        return None
    except (TypeError, ValueError) as exc:
        logger.error("Conversion to numpy failed: %s", exc)
        raise RuntimeError("Data conversion failed.") from exc


def process_results(filename: str):
    result_file = _validate_filename(filename)
    result_data = _load_result_file(result_file)
    processed_array = _convert_to_numpy(result_data)

    cache_path = (CACHE_DIR / "results_cache.json").resolve()
    cached_value = _read_json_cache(cache_path)

    return {
        "array": processed_array,
        "cached": cached_value,
    }


def _validate_filename(filename: str) -> Path:
    if not isinstance(filename, str) or not filename:
        raise ValueError("Filename must be a non‑empty string.")
    path = Path(filename)
    if path.suffix.lower() not in ALLOWED_EXT:
        raise ValueError(f"Unsupported file extension: {path.suffix}")
    resolved = path.resolve()
    if not _is_within_directory(RESULTS_DIR, resolved):
        raise ValueError("File path is outside the allowed results directory.")
    return resolved

