            raise ValueError("Source is not a regular file")
        if file_stat.st_size > MAX_FILE_SIZE:
            raise ValueError("Source file exceeds maximum allowed size")
        src_f = os.fdopen(fd, 'rb')
    except Exception:
        os.close(fd)
        raise

    # Validate destination object
    dest_file = self.args.get('dest')
    if not isinstance(dest_file, io.IOBase) or not dest_file.writable():
        raise ValueError("Invalid destination file object")

    bytes_written = 0
    try:
        while True:
            chunk = src_f.read(4096)
            if not chunk:
                break
            dest_file.write(chunk)
            bytes_written += len(chunk)
    except (OSError, IOError) as e:
        logging.error("Error while processing the file: %s", e)
        raise
    finally:
        try:
            src_f.close()
        except Exception:
            pass
        try:
            dest_file.flush()
        except Exception:
            pass

    return bytes_written

