# Configuration
DATA_DIR = os.path.join("data")
BOUNTY_PATH = os.path.join(DATA_DIR, "bounties.json")
LOCK_PATH = BOUNTY_PATH + ".lock"
MAX_BOUNTY_FILE_SIZE = 5 * 1024 * 1024  # 5 MiB

# Require master key
masterKey = os.getenv("MASTER_KEY")
if not masterKey:
    raise RuntimeError("MASTER_KEY environment variable must be set")

# Validation constants
_MAX_DESC_LEN = 1024
_TARGET_REGEX = re.compile(r'^[\w \-]{1,100}$')
_REWARD_MIN = 0

# Concurrency primitives
_mem_lock = threading.Lock()

class FileLock:
    def __init__(self, path):
        self.path = path
        self.file = None

    def __enter__(self):
        self.file = open(self.path, "a+")
        fcntl.flock(self.file.fileno(), fcntl.LOCK_EX)

    def __exit__(self, exc_type, exc_val, exc_tb):
        fcntl.flock(self.file.fileno(), fcntl.LOCK_UN)
        self.file.close()
        self.file = None

def _ensure_data_dir():
    if not os.path.isdir(DATA_DIR):
        try:
            os.makedirs(DATA_DIR, mode=0o700, exist_ok=True)
            os.chmod(DATA_DIR, 0o700)
        except OSError as exc:
            logger.error("Failed to create data directory: %s", exc)
            raise

def _secure_file_write(path, data):
    temp_path = f"{path}.tmp"
    try:
        with open(temp_path, "w", encoding="utf-8") as f:
            json.dump(data, f, separators=(",", ":"))
        os.chmod(temp_path, stat.S_IRUSR | stat.S_IWUSR)  # 0o600
        with FileLock(LOCK_PATH):
            os.replace(temp_path, path)
    except OSError as exc:
        logger.error("Failed to write bounty file: %s", exc)
        if os.path.exists(temp_path):
            os.remove(temp_path)
        raise

def _load_bounties():
    global bountyList
    bountyList = []
    if not os.path.isfile(BOUNTY_PATH):
        return
    try:
        if os.path.getsize(BOUNTY_PATH) > MAX_BOUNTY_FILE_SIZE:
            raise ValueError("Bounty file exceeds maximum allowed size")
        with open(BOUNTY_PATH, "r", encoding="utf-8") as f:
            raw = json.load(f)
    except (OSError, json.JSONDecodeError, ValueError) as exc:
        logger.error("Failed to load bounties (attempting line‑by‑line recovery): %s", exc)
        # Attempt recovery from JSON‑Lines format
        recovered = []
        try:
            with open(BOUNTY_PATH, "r", encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        entry = json.loads(line)
                        if _verify_entry(entry):
                            recovered.append(entry)
                    except json.JSONDecodeError:
                        logger.warning("Skipping malformed bounty entry line.")
        except OSError as e:
            logger.error("Failed to read bounty file for recovery: %s", e)
        bountyList = recovered
        return

    valid = []
    for entry in raw:
        if isinstance(entry, dict) and _verify_entry(entry):
            valid.append(entry)
        else:
            logger.warning("Corrupted bounty entry detected and ignored.")
    bountyList = valid

def _save_bounties():
    with _mem_lock:
        _ensure_data_dir()
        _secure_file_write(BOUNTY_PATH, bountyList)

def _compute_signature(entry):
    msg = f"{entry['id']}|{entry['target']}|{entry['reward']}|{entry['description']}"
    return hmac.new(masterKey.encode(), msg.encode(), sha256).hexdigest()

def _verify_entry(entry):
    required_keys = {"id", "target", "reward", "description", "signature"}
    if not isinstance(entry, dict) or not required_keys.issubset(entry.keys()):
        return False
    expected_sig = _compute_signature(entry)
    return hmac.compare_digest(entry["signature"], expected_sig)

def add_bounty(target, reward, description):
    if not isinstance(target, str) or not _TARGET_REGEX.fullmatch(target):
        logger.info("Invalid target supplied.")
        return None
    if not isinstance(reward, int) or reward < _REWARD_MIN:
        logger.info("Invalid reward supplied.")
        return None
    if not isinstance(description, str) or len(description) > _MAX_DESC_LEN:
        logger.info("Invalid description supplied.")
        return None

    bounty_id = str(uuid.uuid4())
    entry = {
        "id": bounty_id,
        "target": target.strip(),
        "reward": reward,
        "description": description.strip(),
    }
    entry["signature"] = _compute_signature(entry)

    with _mem_lock:
        bountyList.append(entry)
        try:
            _save_bounties()
        except Exception:
            logger.error("Failed to persist new bounty.")
            bountyList.pop()
            return None
    logger.info("Bounty %s added successfully.", bounty_id)
    return entry

def get_bounty(bounty_id):
    if not isinstance(bounty_id, str):
        return None
    with _mem_lock:
        for entry in bountyList:
            if entry.get("id") == bounty_id and _verify_entry(entry):
                result = entry.copy()
                result.pop("signature", None)
                return result
    return None

def remove_bounty(bounty_id):
    if not isinstance(bounty_id, str):
        return False
    with _mem_lock:
        for i, entry in enumerate(bountyList):
            if entry.get("id") == bounty_id:
                removed = bountyList.pop(i)
                try:
                    _save_bounties()
                    logger.info("Bounty %s removed.", bounty_id)
                    return True
                except Exception:
                    logger.error("Failed to persist bounty removal.")
                    bountyList.insert(i, removed)
                    return False
    return False

_load_bounties()

