import os
import re
import sys
import stat
import subprocess
from pathlib import Path

class EncryptionError(RuntimeError):
    pass

def _is_safe_path_component(component: str) -> bool:
    return re.fullmatch(r"[A-Za-z0-9._-]+", component) is not None

def _validate_and_resolve(base_dir: Path, relative_path: str) -> Path:
    if not _is_safe_path_component(relative_path):
        raise ValueError("Invalid filename component.")
    resolved = (base_dir / relative_path).resolve()
    try:
        resolved.relative_to(base_dir.resolve())
    except ValueError:
        raise ValueError("Path traversal detected.")
    return resolved

def _is_secure_directory(path: Path) -> bool:
    mode = path.stat().st_mode
    return not (mode & (stat.S_IWGRP | stat.S_IWOTH))

def _set_executable_permissions(file_path: Path) -> None:
    parent = file_path.parent
    if not _is_secure_directory(parent):
        raise PermissionError("Parent directory permissions are too permissive.")
    os.chmod(file_path, 0o750)

def _run_encryptor(executable: Path, input_zip: Path, output_zip: Path, key: str) -> None:
    if not (executable.is_file() and os.access(executable, os.X_OK)):
        raise FileNotFoundError("Encryptor executable not found or not executable.")
    cmd = [str(executable), str(input_zip), str(output_zip)]
    result = subprocess.run(
        cmd,
        input=key,
        stdout=subprocess.PIPE,
        stderr=subprocess.PIPE,
        text=True,
        close_fds=True,
    )
    if result.returncode != 0:
        sys.stderr.write("Encryption failed.\n")
        raise EncryptionError("Encryption subprocess failed.")

def _resolve_output_path(base_dir: Path, zip_path_str: str) -> Path:
    path = Path(zip_path_str).resolve()
    try:
        path.relative_to(base_dir.resolve())
    except ValueError:
        raise ValueError("Output path outside allowed directory.")
    return path

def _clear_secret_env(var_name: str) -> None:
    os.environ.pop(var_name, None)

def main():
    base_directory = Path.cwd()
    pack_name = os.getenv("PACK_NAME", "")
    zip_pack_path = os.getenv("ZIP_PACK_PATH", "")
    encryption_key = os.getenv("ENCRYPTION_KEY", "")
    secondary_encryption_key = os.getenv("SECONDARY_ENCRYPTION_KEY", "")

    _clear_secret_env("ENCRYPTION_KEY")
    _clear_secret_env("SECONDARY_ENCRYPTION_KEY")

    if not all(_is_safe_path_component(v) for v in [pack_name, encryption_key, secondary_encryption_key]):
        raise ValueError("Invalid input parameters.")

    encryptor_path = _validate_and_resolve(base_directory, "encryptor")
    _set_executable_permissions(encryptor_path)

    input_zip = _validate_and_resolve(base_directory, f"{pack_name}_not_encrypted.zip")
    resolved_zip_path = _resolve_output_path(base_directory, zip_pack_path)

    primary_output_zip = resolved_zip_path.with_name(
        resolved_zip_path.name.replace("_not_encrypted.zip", ".zip")
    )
    secondary_output_zip = resolved_zip_path.with_name(
        resolved_zip_path.name.replace("_not_encrypted.zip", ".enc2.zip")
    )

    _run_encryptor(encryptor_path, input_zip, primary_output_zip, encryption_key)
    _run_encryptor(encryptor_path, input_zip, secondary_output_zip, secondary_encryption_key)

if __name__ == "__main__":
    try:
        main()
    except Exception:
        sys.stderr.write("An error occurred during processing.\n")
        sys.exit(1)

