def _fetch_private_cert(self, oauth_request):
    """
    Retrieve the PEM‑encoded private key associated with the OAuth request.

    The function validates and sanitizes the incoming request,
    resolves the certificate path in a directory that is owned by the
    application, checks file permissions, and reads the file using safe defaults.
    """
    if not isinstance(oauth_request, dict):
        raise ValueError("Invalid request format")

    client_id = oauth_request.get("client_id")
    if not client_id or not isinstance(client_id, str):
        raise ValueError("Missing or malformed client_id")

    if len(client_id) > MAX_CLIENT_ID_LENGTH:
        raise ValueError("client_id too long")

    if not re.fullmatch(r"[A-Za-z0-9_-]+", client_id):
        raise ValueError("client_id contains illegal characters")

    base_dir = os.path.realpath(
        os.path.abspath(os.path.join(os.path.dirname(__file__), "private_certs"))
    )
    cert_path = os.path.realpath(
        os.path.abspath(os.path.join(base_dir, f"{client_id}.pem"))
    )

    if not cert_path.startswith(base_dir + os.sep):
        raise ValueError("Resolved certificate path is invalid")

    try:
        st = os.stat(cert_path)
        if st.st_mode & 0o077:
            raise PermissionError("Certificate file permissions are too permissive")
    except FileNotFoundError as exc:
        raise FileNotFoundError("Requested certificate not found") from exc

    try:
        with open(cert_path, "rb") as cert_file:
            cert_bytes = cert_file.read()

        if b"PRIVATE KEY" not in cert_bytes:
            raise ValueError("Certificate content does not contain a private key")

        return cert_bytes

    except PermissionError as exc:
        raise PermissionError("Insufficient permissions to read certificate") from exc
    except Exception as exc:
        logger.exception("Failed to retrieve private certificate")
        raise RuntimeError("Failed to retrieve private certificate") from exc

