class ConfigLoader:
    def __init__(self, config):
        self._validate_host(config.get("host"))
        self._validate_port(config.get("port"))
        self._load_langfile(config)

    def _validate_host(self, host):
        if not isinstance(host, str) or not host.strip():
            raise ValueError("Invalid configuration: 'host' must be a non‑empty string")
        host = host.strip()
        if not HOST_RE.fullmatch(host):
            raise ValueError(f"Invalid configuration: 'host' is not a valid hostname or IP address: {host}")
        self.host = host

    def _validate_port(self, port):
        try:
            port_int = int(port)
        except Exception:
            raise ValueError("Invalid configuration: 'port' must be an integer")
        if not (1 <= port_int <= 65535):
            raise ValueError("Invalid configuration: 'port' out of range (1‑65535)")
        self.port = port_int

    def _load_langfile(self, config):
        lang_name = config.get("langfile", "")
        if not isinstance(lang_name, str):
            raise ValueError("Invalid configuration: 'langfile' must be a string")
        candidate = (BASE_LANG_DIR / lang_name).expanduser().resolve()
        if not str(candidate).startswith(str(BASE_LANG_DIR) + os.sep):
            raise ValueError("Language file must reside within the permitted directory")
        try:
