import re
import logging
import sqlite3

def _is_valid_identifier(name: str) -> bool:
    """Validate that a name is a proper SQL identifier."""
    return bool(re.fullmatch(r'[A-Za-z_][A-Za-z0-9_]*', name))

def _is_valid_table_define(definition: str) -> bool:
    """
    Validate column definitions.
    Allows column name + type (INTEGER, TEXT, REAL, BLOB) with optional
    PRIMARY KEY, NOT NULL, UNIQUE constraints. Rejects any other tokens.
    """
    allowed_types = {"INTEGER", "TEXT", "REAL", "BLOB"}
    allowed_constraints = {"PRIMARY", "KEY", "NOT", "NULL", "UNIQUE"}
    parts = [p.strip() for p in definition.split(",") if p.strip()]
    for part in parts:
        # Split column definition into name, type, and the rest
        tokens = part.split()
        if len(tokens) < 2:
            return False
        col_name, col_type, *rest = tokens
        if not _is_valid_identifier(col_name):
            return False
        if col_type.upper() not in allowed_types:
            return False
        # Validate optional constraints
        for token in rest:
            if token.upper() not in allowed_constraints:
                return False
    return True

def create_table(dbname: str, table: str, table_define: str) -> bool:
    """
    Create a table with the given definition after strict validation.
    Returns True on success.
    """
    # Input type validation
    if not all(isinstance(arg, str) for arg in (dbname, table, table_define)):
        raise TypeError("Database name, table name, and table definition must be strings")

    # Identifier validation
    if not _is_valid_identifier(table):
        raise ValueError(
            "Invalid table name: must contain only letters, numbers, and underscores, and not start with a number"
        )

    # Column definition validation
    if not _is_valid_table_define(table_define):
        raise ValueError("Invalid table definition format")

    db = None
    cu = None
    try:
        db = sqlite3.connect(dbname)
        cu = db.cursor()
        cu.execute(f"CREATE TABLE IF NOT EXISTS {table} ({table_define})")
        db.commit()
        return True
    except sqlite3.Error as e:
        logging.error("Failed to create table in database: %s", e)
        raise
    finally:
        if cu is not None:
            try:
                cu.close()
            except Exception:
                pass
        if db is not None:
            try:
                db.close()
            except Exception:
                pass

