def volume_alsa(vol: str) -> Optional[str]:
    """
    Adjust ALSA volume safely.

    Accepted commands:
        - 'up'   : increase volume by 5%
        - 'down' : decrease volume by 5%
        - 'set:<0-100>' : set absolute volume percentage
    """
    if not isinstance(vol, str):
        raise ValueError("Volume command must be a string")

    if vol == "up":
        cmd = ["amixer", "-M", "set", "Master", "5%+"]
    elif vol == "down":
        cmd = ["amixer", "-M", "set", "Master", "5%-"]
