            level_str = vol.split(":", 1)[1]
            level = int(level_str)
        except (ValueError, IndexError):
            raise ValueError("Invalid set volume format")
        if not (0 <= level <= 100):
            raise ValueError("Volume level must be between 0 and 100")
        cmd = ["amixer", "-M", "set", "Master", f"{level}%"]
