        raise ValueError("Unsupported volume operation")

    try:
        result = subprocess.run(
            cmd,
            capture_output=True,
            text=True,
            check=True,
            shell=False,
        )
        return result.stdout.strip()
    except subprocess.CalledProcessError:
        logging.error("Failed to adjust ALSA volume")
        return None

