class Indexer:
    def __init__(self, forward_path, inverted_path):
        self.forward_path = forward_path
        self.inverted_path = inverted_path
        self.forwardIndex = self._load_index(self.forward_path)
        self.invertedIndex = self._load_index(self.inverted_path)

    def _load_index(self, path):
        try:
            if os.path.exists(path):
