def _ensure_secure_dir(path: pathlib.Path) -> None:
    """Create directory with 0700 permissions and verify ownership."""
    try:
        path.mkdir(parents=True, exist_ok=True)
    except Exception as exc:
        raise RuntimeError("Failed to create storage directory") from exc

    # Verify permissions are at most 0700
    current_mode = stat.S_IMODE(path.stat().st_mode)
    if current_mode & 0o777 != 0o700:
        try:
            path.chmod(0o700)
        except Exception as exc:
            raise RuntimeError("Failed to set directory permissions") from exc

    # Verify ownership belongs to the current user
    try:
        dir_uid = path.stat().st_uid
        if dir_uid != os.getuid():
            raise RuntimeError("Storage directory is not owned by the current user")
    except Exception as exc:
        raise RuntimeError("Failed to verify storage directory ownership") from exc

def _write_json_atomic(file_path: pathlib.Path, data) -> None:
    """Write JSON data to a file atomically with mode 0600."""
    json_bytes = json.dumps(data, separators=(",", ":"), ensure_ascii=False).encode("utf-8")
    dir_fd = os.open(file_path.parent, os.O_RDONLY)
    try:
        # Use O_EXCL to avoid race condition with existing file or symlink
        fd = os.open(
            str(file_path),
            os.O_WRONLY | os.O_CREAT | os.O_EXCL,
            0o600,
        )
        try:
            os.write(fd, json_bytes)
        finally:
            os.close(fd)
    except FileExistsError as exc:
        raise RuntimeError(f"Target file already exists: {file_path}") from exc
