from numpy.testing import assert_equal


class RestrictedUnpickler(pickle.Unpickler):
    ALLOWED_GLOBALS = {
        "builtins": {
            "set",
            "frozenset",
            "list",
            "dict",
            "tuple",
            "int",
            "float",
            "str",
            "bool",
            "bytes",
        },
        "numpy.core.multiarray": {"_reconstruct", "ndarray"},
        "numpy": {"dtype"},
    }

    def find_class(self, module, name):
        # Allow any class from the numpy package (required for ndarray handling)
        if module.startswith("numpy"):
            return super().find_class(module, name)

        allowed_names = self.ALLOWED_GLOBALS.get(module)
        if allowed_names and name in allowed_names:
            return super().find_class(module, name)

        raise pickle.UnpicklingError(f"global '{module}.{name}' is forbidden")


def safe_loads(data: bytes):
    """Deserialize bytes using a restricted unpickler."""
    return RestrictedUnpickler(io.BytesIO(data)).load()


