class ConfigurationError(ValueError):
    """Raised when configuration validation fails."""
    pass

def _validate_ip(ip: str) -> None:
    try:
        ipaddress.ip_address(ip)
    except ValueError as exc:
        raise ConfigurationError("Invalid SAN IP address") from exc

def _validate_login(login: str) -> None:
    if not re.fullmatch(r"[A-Za-z0-9._-]+", login):
        raise ConfigurationError("Invalid SAN login; only alphanumeric characters, dot, underscore, and hyphen are allowed")

def _validate_password(pw: str) -> None:
    if not pw:
        raise ConfigurationError("SAN password must not be empty")
    # Example policy: at least 8 characters, include letters and numbers
    if len(pw) < 8 or not re.search(r"[A-Za-z]", pw) or not re.search(r"\d", pw):
        raise ConfigurationError("SAN password does not meet complexity requirements")

def _validate_privilege(privilege: str) -> None:
    allowed = {"read-only", "read-write"}
    if privilege not in allowed:
        raise ConfigurationError(f"Driver privilege must be one of {allowed}")

