_MAX_DEPTH = 5
_MAX_ITEMS = 10000
_SAFE_TYPES = (int, float, complex, str, bool, type(None), list, tuple, dict, set)

_ALLOWED_FUNCS = {
    "abs": abs,
    "round": round,
    "min": min,
    "max": max,
    "sum": sum,
    "len": len,
    "pow": pow,
}
_ALLOWED_FUNCS.update({name: getattr(math, name) for name in dir(math) if not name.startswith("_")})

_ALLOWED_NODES = (
    ast.Expression,
    ast.BoolOp,
    ast.BinOp,
    ast.UnaryOp,
    ast.Compare,
    ast.Call,
    ast.Name,
    ast.Load,
    ast.Constant,
    ast.Subscript,
    ast.Index,
    ast.Slice,
    ast.List,
    ast.Tuple,
    ast.Dict,
)


def _is_safe_value(v):
    if isinstance(v, _SAFE_TYPES):
        if isinstance(v, (list, tuple, set)):
            return all(_is_safe_value(i) for i in v)
        if isinstance(v, dict):
            return all(
                isinstance(k, (str, int, float)) and _is_safe_value(val)
                for k, val in v.items()
            )
        return True
    return False


def _validate_structure(value, depth=0, counter=None):
    if counter is None:
        counter = [0]
    if depth > _MAX_DEPTH:
        raise ValueError(f"Maximum container depth {_MAX_DEPTH} exceeded")
    if isinstance(value, (list, tuple, set)):
        for item in value:
            counter[0] += 1
            if counter[0] > _MAX_ITEMS:
                raise ValueError(f"Maximum number of items {_MAX_ITEMS} exceeded")
            _validate_structure(item, depth + 1, counter)
    elif isinstance(value, dict):
        for k, v in value.items():
            if not isinstance(k, (str, int, float)):
                raise TypeError(f"Unsafe dict key type: {type(k).__name__}")
            counter[0] += 1
            if counter[0] > _MAX_ITEMS:
                raise ValueError(f"Maximum number of items {_MAX_ITEMS} exceeded")
            _validate_structure(v, depth + 1, counter)
    elif not isinstance(value, _SAFE_TYPES):
        raise TypeError(f"Unsafe parameter type: {type(value).__name__}")


