def _validate_routine(name: str, direction: str) -> str:
    if not isinstance(name, str):
        raise TypeError(f'{direction.capitalize()} routine name must be a string')
    if name not in _allowed_routines:
        raise ValueError(f'Invalid {direction} routine specified: {name}')
    return _allowed_routines[name]

def _validate_interval(interval):
    if not isinstance(interval, (int, float)):
        raise TypeError('Interval must be a numeric value')
    return interval

def _sanitize_kwargs(kwargs):
    sanitized = {k: v for k, v in kwargs.items() if k in _allowed_kwargs}
    if 'latitude' in sanitized and not isinstance(sanitized['latitude'], (int, float)):
        raise TypeError('Latitude must be a number')
    if 'longitude' in sanitized and not isinstance(sanitized['longitude'], (int, float)):
        raise TypeError('Longitude must be a number')
    return sanitized

def compute_radiation(self, routine_up: str, routine_down: str, interval, **kwargs):
    """
    Compute upward and downward shortwave radiation using validated routines and parameters.
    """
    # Validate and resolve routine method names
    up_method_name = _validate_routine(routine_up, 'upward')
    down_method_name = _validate_routine(routine_down, 'downward')

    # Retrieve callables safely
    up_method = getattr(self, up_method_name, None)
    down_method = getattr(self, down_method_name, None)

    if not callable(up_method):
        raise AttributeError(f'Upward method {up_method_name} not found on {self.__class__.__name__}')
    if not callable(down_method):
        raise AttributeError(f'Downward method {down_method_name} not found on {self.__class__.__name__}')

    # Validate interval
    interval = _validate_interval(interval)

    # Sanitize and validate keyword arguments
    sanitized_kwargs = _sanitize_kwargs(kwargs)

    # Execute the routines with safe parameters
    try:
        sw_down = down_method(interval=interval, **sanitized_kwargs)
