from typing import Union


def sha1_hex_file(filepath: Union[str, bytes, Path], max_bytes: int | None = None) -> str:
    """
    Returns the SHA‑256 hexadecimal digest of a file's contents.

    Parameters
    ----------
    filepath : str, bytes, or pathlib.Path
        Path to the file to hash.
    max_bytes : int, optional
        If provided, at most this many bytes are read from the file.

    Raises
    ------
    TypeError
        If `filepath` is not a string, bytes, or Path, or if `max_bytes` is not an int.
    ValueError
        If `max_bytes` is negative, if the path does not point to a regular file,
        or if the file changes between path resolution and opening.
    IOError
        If the file cannot be opened or read.
    """
    # Normalise the input to a Path object
    if isinstance(filepath, (str, bytes)):
        file_path = Path(filepath)
    elif isinstance(filepath, Path):
        file_path = filepath
    else:
        raise TypeError("filepath must be a string, bytes, or Path object")

    # Resolve the path, eliminating symlinks and relative components
    try:
        resolved_path = file_path.resolve(strict=True)
    except FileNotFoundError as exc:
        raise FileNotFoundError(f"File not found: {filepath}") from None
    except RuntimeError as exc:
        raise ValueError("Unable to resolve path (possible symlink loop)") from None

    # Ensure the target is a regular file
    if not resolved_path.is_file():
        raise ValueError(f"Path is not a regular file: {resolved_path}")

    # Validate max_bytes argument
    if max_bytes is not None:
        if not isinstance(max_bytes, int):
            raise TypeError("max_bytes must be an integer")
        if max_bytes < 0:
            raise ValueError("max_bytes must be non‑negative")

    # Prepare hash algorithm (SHA‑256 replaces weak SHA‑1)
    digest = hashlib.sha256()
    chunk_size = 8192  # 8 KiB

    # Open the file atomically, refusing symlinks (O_NOFOLLOW) where supported
    flags = os.O_RDONLY
    if hasattr(os, "O_NOFOLLOW"):
        flags |= os.O_NOFOLLOW

    try:
        fd = os.open(str(resolved_path), flags)
    except OSError as exc:
        raise IOError("Failed to open file") from None

    try:
        # Verify the file has not changed between resolve and open
        try:
            stat_fd = os.fstat(fd)
            stat_path = resolved_path.stat()
        except OSError as exc:
            raise IOError("Failed to stat file") from None

        if (stat_fd.st_ino != stat_path.st_ino) or (stat_fd.st_dev != stat_path.st_dev):
            raise IOError("File changed between resolve and open")

        with os.fdopen(fd, "rb") as f:
            bytes_remaining = max_bytes
            while True:
                if bytes_remaining is not None:
                    to_read = min(chunk_size, bytes_remaining)
                    data = f.read(to_read)
                    bytes_remaining -= len(data)
                else:
                    data = f.read(chunk_size)

                if not data:
                    break

                digest.update(data)

                if bytes_remaining is not None and bytes_remaining <= 0:
                    break
    except OSError as exc:
        raise IOError("Failed to read file") from None
    finally:
        # Ensure the file descriptor is closed if an exception occurred before fdopen
        try:
            os.close(fd)
        except Exception:
            pass

    return digest.hexdigest()

