# Define a whitelist of allowed built‑in functions for the sandbox
_ALLOWED_BUILTINS = {
    # safe built‑ins can be added here, e.g.:
    "abs": abs,
    "len": len,
    "min": min,
    "max": max,
    "sum": sum,
