_BASE_DIR = os.getcwd()


class DoctestExecutionError(RuntimeError):
    """Raised when execution of a doctest example fails."""


def _is_module_path_allowed(module):
    """Return True if the module's __file__ resides within the allowed base directory."""
    module_path = getattr(module, "__file__", None)
    if not module_path:
        return False
    return os.path.abspath(module_path).startswith(os.path.abspath(_BASE_DIR))


def _run_in_sandbox(code: str) -> dict:
    """
    Execute *code* in a separate, heavily restricted Python subprocess.

    Returns a dictionary containing the locals produced by the code.
    """
    sandbox_script = """
import sys, json

code = sys.stdin.read()

allowed_builtins = {allowed_builtins}
globals_dict = {"__builtins__": allowed_builtins}
locals_dict = {{}}
exec(compile(code, "<doctest>", "exec"), globals_dict, locals_dict)

def _safe_serialize(obj):
    try:
        json.dumps(obj)
        return obj
    except TypeError:
        return repr(obj)

result = {{k: _safe_serialize(v) for k, v in locals_dict.items() if not k.startswith("__")}}
print(json.dumps(result))
""".format(
        allowed_builtins=repr(_ALLOWED_BUILTINS)
    )

    try:
        proc = subprocess.run(
            [sys.executable, "-c", sandbox_script],
            input=code,
            capture_output=True,
            text=True,
            timeout=2,
            check=True,
        )
    except subprocess.TimeoutExpired as exc:
        raise DoctestExecutionError("Doctest execution timed out") from exc
    except subprocess.CalledProcessError as exc:
        raise DoctestExecutionError(f"Doctest subprocess failed: {exc.stderr.strip()}") from exc

    try:
        return json.loads(proc.stdout)
    except json.JSONDecodeError as exc:
        raise DoctestExecutionError("Failed to decode sandbox output") from exc


def _exec_doctest_func(modname: str, funcname: str) -> dict | None:
    """
    Execute the first doctest example of a function in a secure, isolated sandbox.

    Returns a dictionary of the locals created by the doctest, or ``None`` if
    the function has no doctest examples.
    """
    # ----- Input validation -------------------------------------------------
    if not isinstance(modname, str) or not isinstance(funcname, str):
        raise TypeError("Module name and function name must be strings")
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_.]*", modname):
        raise ValueError("Invalid module name")
    if not re.fullmatch(r"[A-Za-z_][A-Za-z0-9_]*", funcname):
        raise ValueError("Invalid function name")

    # ----- Secure import ----------------------------------------------------
    try:
        module = importlib.import_module(modname)
    except Exception as exc:
        raise ImportError(f"Failed to import module {modname}") from exc

    if not _is_module_path_allowed(module):
        raise ImportError(f"Import of module {modname} is not permitted")

    # ----- Retrieve function -------------------------------------------------
    try:
        func = getattr(module, funcname)
    except AttributeError as exc:
        raise AttributeError(f"Function {funcname} not found in module {modname}") from exc

