ALLOWED_ROOT = pathlib.Path("/srv/artifacts").resolve()

def _is_relative_to(path: pathlib.Path, base: pathlib.Path) -> bool:
    try:
        return path.is_relative_to(base)  # type: ignore[attr-defined]
    except AttributeError:
        try:
            return str(path.resolve()).startswith(str(base) + os.sep)
        except Exception:
            return False

def copy_artifacts(source_path: str, destination_path: str) -> str:
    """
    Securely copy a directory tree from source_path to destination_path.
    The destination must reside within ALLOWED_ROOT.
    """
    try:
        src = pathlib.Path(source_path).expanduser().resolve(strict=True)
        dst = pathlib.Path(destination_path).expanduser().resolve(strict=False)
    except Exception as e:
        logging.error("Invalid source or destination path.")
        raise ValueError("Invalid source or destination path.") from e

    if not src.is_dir():
        logging.error("Source path is not a directory: %s", src)
        raise ValueError("Source path must be an existing directory.")

    # Ensure source does not contain unsafe symlinks
    for root, dirs, files in os.walk(src, followlinks=False):
        for entry in dirs + files:
            entry_path = pathlib.Path(root) / entry
            if entry_path.is_symlink():
                target = entry_path.resolve()
                if not _is_relative_to(target, src):
                    logging.error("Symlink %s points outside the source tree.", entry_path)
                    raise ValueError("Source contains symlink pointing outside allowed directory.")

    if not _is_relative_to(dst, ALLOWED_ROOT):
        logging.error("Destination %s is outside allowed root %s.", dst, ALLOWED_ROOT)
        raise ValueError("Destination must be inside the allowed root directory.")

    dst_parent = dst.parent
    try:
        dst_parent.mkdir(parents=True, exist_ok=True, mode=0o700)
    except Exception as e:
        logging.error("Failed to create destination directory %s.", dst_parent)
        raise PermissionError("Cannot create destination directory.") from e

    if not os.access(dst_parent, os.W_OK):
        logging.error("Insufficient write permissions for destination: %s", dst_parent)
        raise PermissionError("Cannot write to destination directory.")

    if dst.exists():
        logging.error("Destination already exists: %s", dst)
        raise FileExistsError("Destination path already exists.")

    try:
        shutil.copytree(src, dst, dirs_exist_ok=False, copy_function=shutil.copy2)
        logging.info("Artifacts successfully copied from %s to %s", src, dst)
    except Exception as e:
        logging.error("Failed to copy artifacts from %s to %s.", src, dst)
        raise IOError("Error copying artifacts.") from e

    return str(dst.resolve())

