    # POST method – actual execution
    payment_id = request.form.get("paymentId")
    payer_id = request.form.get("PayerID")
    if not payment_id or not payer_id:
        flash("Missing payment identifiers.", "error")
        return redirect(url_for("index"))

    payment = paypalrestsdk.Payment.find(payment_id)
    try:
        if payment.execute({"payer_id": payer_id}):
            flash("Payment completed successfully.", "success")
        else:
            safe_log_error(payment.error)
            flash("Payment could not be completed.", "error")
    except Exception:
        app.logger.exception("Exception during payment execution")
        flash("An unexpected error occurred.", "error")
    return redirect(url_for("index"))


