import os
import sys
import stat
import hashlib
import hmac

def _read_secure_file(path: str, description: str) -> bytes:
    try:
        st = os.stat(path)
        if st.st_mode & (stat.S_IRWXG | stat.S_IRWXO):
            raise PermissionError(f"{description} file '{path}' must not be group/other accessible")
        with open(path, "rb") as f:
            return f.read()
    except Exception as exc:
        raise RuntimeError(f"Failed to read {description}: {exc}")

def _load_hmac_key() -> bytes:
    key_path = os.getenv("HMAC_KEY_FILE", "/etc/hmac_key")
    return _read_secure_file(key_path, "HMAC key")

def _load_expected_hmac() -> bytes:
    hmac_path = os.getenv("EXPECTED_HMAC_FILE", "/etc/expected_hmac")
    data = _read_secure_file(hmac_path, "expected HMAC")
    if len(data) != hashlib.sha256().digest_size:
        raise ValueError("Expected HMAC must be a 32‑byte SHA‑256 digest")
    return data

def _read_input() -> bytes:
    data = sys.stdin.buffer.read()
    if not data:
        raise ValueError("No input data provided")
    return data

def main() -> None:
    try:
        out = _read_input()
        key = _load_hmac_key()
        expected_hmac = _load_expected_hmac()
        computed_hmac = hmac.new(key, out, hashlib.sha256).digest()
        if not hmac.compare_digest(computed_hmac, expected_hmac):
            sys.stderr.write("Integrity verification failed.\n")
            sys.exit(1)
        sys.stdout.buffer.write(out)
    except Exception:
        sys.stderr.write("Error: An internal error occurred.\n")
        sys.exit(1)

