class Response:
    def __init__(self, request, stream):
        self.request = request
        self._stream = stream
        self._headers = {}
        self._status_code = 200
        self._buffer = b""
        self._headers_written = False
        self._finished = False

    def _log_error(self, message: str) -> None:
        import sys
        sys.stderr.write(f"{message}\n")

    def write(self, data: bytes) -> None:
        if not isinstance(data, (bytes, bytearray)):
            raise TypeError("Response data must be bytes")
        self._buffer += data

    def finish(self) -> None:
        if not self._headers_written:
            if (
                self._status_code == 200
                and getattr(self.request, "method", "").upper() == "GET"
                and "ETag" not in self._headers
            ):
                import hashlib
                body_bytes = (
                    self._buffer
                    if isinstance(self._buffer, (bytes, bytearray))
                    else b""
                )
                etag_hash = hashlib.sha256(body_bytes).hexdigest()
                self._headers["ETag"] = f'"{etag_hash}"'

            if "Content-Length" not in self._headers:
                body_len = len(self._buffer) if hasattr(self._buffer, "__len__") else 0
                self._headers["Content-Length"] = str(body_len)

            self._headers_written = True

        if self._buffer:
            try:
                if hasattr(self._stream, "write"):
                    self._stream.write(self._buffer)
                if hasattr(self._stream, "flush"):
                    self._stream.flush()
            except Exception:
                self._log_error("Error writing response body")
                try:
                    self._stream.close()
                finally:
                    raise

        self._finished = True

        if not getattr(self.request, "keep_alive", False):
            try:
                self._stream.close()
            except Exception:
                self._log_error("Error closing response stream")

