    The path must also match an allowed whitelist pattern.
    """
    base_dir = Path(current_app.instance_path).resolve()
    target_path = Path(db_path).resolve()

    # Ensure the path resides within the base directory
    try:
        common = Path(os.path.commonpath([str(base_dir), str(target_path)]))
    except Exception:
        raise ValueError("Unable to determine common path for validation")
    if common != base_dir:
        raise ValueError("Database path is outside allowed directory")

    # Validate allowed characters (relative to base_dir)
    relative = target_path.relative_to(base_dir)
    if not _PATH_RE.fullmatch(str(relative)):
        raise ValueError("Database path contains disallowed characters")

    return str(target_path)

@app.before_request
def before_request():
    """Establish a SQLite connection and attach auxiliary databases safely."""
    try:
