def _wrap_process(pipe: io.IOBase, proc: subprocess.Popen, timeout: Optional[float]) -> io.TextIOBase:
    class _ProcessIO(io.TextIOBase):
        def __init__(self, pipe: io.IOBase, proc: subprocess.Popen, timeout: Optional[float]) -> None:
            self._pipe = pipe
            self._proc = proc
            self._timeout = timeout
            self._closed = False

        def read(self, *args, **kwargs):
            return self._pipe.read(*args, **kwargs)

        def readline(self, *args, **kwargs):
            return self._pipe.readline(*args, **kwargs)

        def readlines(self, *args, **kwargs):
            return self._pipe.readlines(*args, **kwargs)

        def write(self, s):
            return self._pipe.write(s)

        def flush(self):
            return self._pipe.flush()

        def close(self):
            if not self._closed:
                try:
                    self._pipe.close()
                    try:
                        self._proc.wait(timeout=self._timeout)
                    except subprocess.TimeoutExpired:
                        self._proc.kill()
                        self._proc.wait()
                finally:
                    self._closed = True

        @property
        def closed(self):
            return self._closed

    return _ProcessIO(pipe, proc, timeout)


