def _is_command_allowed(command):
    if not isinstance(command, (list, tuple)):
        raise ValueError("Command must be provided as a list or tuple")
    if not command:
        raise PermissionError("Empty command is not allowed")

    cmd = command[0]
    if cmd not in ALLOWED_COMMANDS:
