#!/usr/bin/env python3
import sys
import subprocess
import ipaddress
import time
from scapy.all import arping, Ether, ARP, sendp, conf

MAX_TARGETS = 50
INTER_TARGET_DELAY = 0.1

def validate_network(net_str):
    try:
        net = ipaddress.ip_network(net_str, strict=False)
        if net.version != 4:
            raise ValueError
        return net
    except ValueError:
        sys.stderr.write("Invalid network specification.\n")
        sys.exit(1)

def validate_ip(ip_str, network):
    try:
        ip = ipaddress.ip_address(ip_str)
        if ip.version != 4:
            raise ValueError
        if ip not in network:
            sys.stderr.write("Gateway IP is not in the specified network.\n")
            sys.exit(1)
        return ip
    except ValueError:
        sys.stderr.write("Invalid gateway IP.\n")
        sys.exit(1)

def discover_live_hosts(network):
    nmap_cmd = ["nmap", "-sn", str(network)]
    try:
        nmap_output = subprocess.check_output(
            nmap_cmd, universal_newlines=True, timeout=30
        )
    except subprocess.CalledProcessError:
        sys.stderr.write("Nmap scan failed.\n")
        sys.exit(1)
    except subprocess.TimeoutExpired:
        sys.stderr.write("Nmap scan timed out.\n")
        sys.exit(1)

    live = []
    for line in nmap_output.splitlines():
        if "Nmap scan report for" in line:
            parts = line.split()
            candidate = parts[-1]
            try:
                ip = ipaddress.ip_address(candidate)
                if ip.version == 4:
                    live.append(str(ip))
            except ValueError:
                continue
    return live

def resolve_mac(target_ip):
    ans, _ = arping(target_ip, timeout=2, verbose=False)
    if not ans:
        return None
    for _, rcv in ans:
        if hasattr(rcv, "hwsrc"):
            return rcv.hwsrc
    return None

def main():
    if len(sys.argv) != 3:
        sys.stderr.write(f"Usage: {sys.argv[0]} <network_cidr> <gateway_ip>\n")
        sys.exit(1)

    ipnet_str = sys.argv[1]
    dgip_str = sys.argv[2]

    network = validate_network(ipnet_str)
    dgip = validate_ip(dgip_str, network)

    live_ips = discover_live_hosts(network)
    if not live_ips:
        sys.stderr.write("No live hosts detected.\n")
        sys.exit(1)

    conf.verb = 0

    gateway_mac = resolve_mac(str(dgip))
    if not gateway_mac:
        sys.stderr.write("Unable to obtain gateway MAC address.\n")
        sys.exit(1)

    for i, target_ip in enumerate(live_ips):
        if i >= MAX_TARGETS:
            break
        target_mac = resolve_mac(target_ip)
        if not target_mac:
            sys.stderr.write(f"Could not resolve MAC for {target_ip}, skipping.\n")
            continue

        arp_reply = Ether(dst=target_mac) / ARP(
            op=2,
            psrc=str(dgip),
            pdst=target_ip,
            hwsrc=gateway_mac,
            hwdst=target_mac,
        )
        try:
            sendp(arp_reply, count=3, inter=0.2, verbose=False)
            print(f"Spoofed {target_ip}")
        except Exception:
            sys.stderr.write(f"Failed to send spoof packet to {target_ip}.\n")
        time.sleep(INTER_TARGET_DELAY)

if __name__ == "__main__":
    main()

