def clean_paths(paths, verbose=False):
    allowed_base = Path(os.getenv('SAFE_CLEANUP_BASE', '/tmp')).resolve()
    for path in paths:
        try:
            target = Path(path).resolve()
            if not (target == allowed_base or allowed_base in target.parents):
