def _sanitize_int(value: Union[int, str]) -> int:
    """
    Validate and convert a value to a non‑negative integer.

    Args:
        value: The value to validate. May be an int or a numeric string.

    Returns:
        int: The validated integer.

    Raises:
        ValueError: If the value is a boolean, negative, or cannot be converted to an int.
        TypeError: If the value is of an unsupported type.
    """
    if isinstance(value, bool):
        raise ValueError("Invalid boolean for day count")
    if isinstance(value, int):
        iv = value
    elif isinstance(value, str):
        try:
            iv = int(value)
        except Exception as exc:
            raise ValueError("daypassed must be an integer") from exc
    else:
        raise TypeError("daypassed must be an int or numeric string")

    if iv < 0:
        raise ValueError("daypassed cannot be negative")
    return iv

def makinGetYear() -> str:
    """Return the current year as a zero‑padded string."""
    return datetime.now().strftime('%Y')

def makinGetMonth() -> str:
    """Return the current month as a zero‑padded string."""
    return datetime.now().strftime('%m')

def makinGetDay() -> str:
    """Return the current day of the month as a zero‑padded string."""
    return datetime.now().strftime('%d')

def _compute_target_date(days: int) -> datetime:
    """
    Compute the target date by subtracting a number of days from now.

    Args:
        days: Number of days to subtract (non‑negative integer).

    Returns:
        datetime: The computed target datetime.

    Raises:
        ValueError: If the resulting date is out of the supported range.
    """
    try:
        target = datetime.now() - timedelta(days=days)
    except OverflowError as exc:
        raise ValueError("Resulting date is out of range") from exc
    return target

def makinGetPrevYear(daypassed: Union[int, str]) -> str:
    """Return the year component of the date *daypassed* days ago."""
    days = _sanitize_int(daypassed)
    target = _compute_target_date(days)
    return target.strftime('%Y')

