import urllib.parse
import json
import logging

def execute_asset_type_flow(self, method, url, new_asset_type_body):
    if not isinstance(method, str):
        raise TypeError("method must be a string")
    allowed_methods = {"POST", "DELETE"}
    if method.upper() not in allowed_methods:
        raise ValueError(f"Unsupported method: {method}")

    parsed_url = urllib.parse.urlparse(url)
    if parsed_url.scheme not in ("http", "https") or not parsed_url.netloc:
        raise ValueError(f"Invalid URL: {url}")

    if isinstance(new_asset_type_body, dict):
        try:
            request_body = json.dumps(new_asset_type_body, separators=(",", ":"), ensure_ascii=False)
        except (TypeError, ValueError) as exc:
            raise ValueError("new_asset_type_body contains non‑serializable values") from exc
    elif isinstance(new_asset_type_body, (str, bytes, bytearray)):
        if isinstance(new_asset_type_body, (bytes, bytearray)):
            try:
                body_str = new_asset_type_body.decode("utf-8", errors="strict")
            except UnicodeDecodeError as exc:
                raise ValueError("new_asset_type_body bytes must be UTF‑8 decodable") from exc
        else:
            body_str = new_asset_type_body
        try:
            json.loads(body_str)
        except json.JSONDecodeError as exc:
            raise ValueError("new_asset_type_body must be valid JSON") from exc
        request_body = body_str
    else:
        raise TypeError("new_asset_type_body must be dict or JSON string/bytes")

    try:
        post_resp = self.app.post(
            "/api/assets/types",
            content_type="application/json",
            data=request_body,
        )
    except Exception as exc:
        self.logger.exception("POST request failed")
        self.fail(f"POST request raised exception: {exc}")

    if post_resp.status_code != 201:
        self.logger.error(
            "[%s] Asset type creation failed, status: %s", method, post_resp.status_code
        )
        self.fail(f"Asset type creation failed with status {post_resp.status_code}")

    try:
        rv = self.app.delete(url)
    except Exception as exc:
        self.logger.exception("[%s] Exception during DELETE request", method)
        self.fail(f"Exception during DELETE: {exc}")

    if rv.status_code not in (200, 202, 204):
        self.logger.error(
            "[%s] DELETE request returned unexpected status: %s", method, rv.status_code
        )
        self.fail(f"DELETE failed with status {rv.status_code}")

    del_response = (
        rv.data.decode("utf-8")
        if isinstance(rv.data, (bytes, bytearray))
        else str(rv.data)
    )
    self.logger.debug("[%s] Raw delete response: %s", method, del_response)

    try:
        del_json = json.loads(del_response)
    except json.JSONDecodeError:
        del_json = None
    self.logger.debug("[%s] Parsed delete response JSON: %s", method, del_json)

    self.assertIsNotNone(del_response, "No response")
    self.assertIn(rv.status_code, (200, 202, 204), "Unexpected delete status code")

import sys
import re
import hashlib

MAX_INPUT_LENGTH = 4096
_ALLOWED_PATTERN = re.compile(r'^[\x20-\x7E]*$')


def _read_input(max_len=MAX_INPUT_LENGTH):
    try:
        raw = sys.stdin.buffer.read(max_len + 1)
        if len(raw) > max_len:
            raise ValueError("Input exceeds maximum allowed length")
        try:
            text = raw.decode('utf-8')
        except UnicodeDecodeError as exc:
            raise ValueError("Input is not valid UTF-8") from exc
        if not _ALLOWED_PATTERN.fullmatch(text):
            raise ValueError("Input contains disallowed characters")
        return text
    except Exception:
        sys.stderr.write("Failed to read input\n")
        sys.exit(1)


def _hash_data(data):
    return hashlib.sha256(data.encode('utf-8')).hexdigest()


def main():
    user_input = _read_input()
    digest = _hash_data(user_input)
    print(digest)


if __name__ == "__main__":
    main()
